// CardinalityLimiter enforces a maximum number of distinct label value combinations
// to prevent cardinality explosion from user-provided input.
type CardinalityLimiter struct {
	mu          sync.RWMutex
	seen        map[string]struct{}
	maxSeries   int
	overflowCnt int64
}

func NewCardinalityLimiter(maxSeries int) *CardinalityLimiter {
	return &CardinalityLimiter{
		seen:      make(map[string]struct{}),
		maxSeries: maxSeries,
	}
}

// Allow checks whether a new label combination is permitted.
// Returns true if the combination is already tracked or if we haven't hit the limit.
func (cl *CardinalityLimiter) Allow(key string) bool {
	cl.mu.RLock()
	_, exists := cl.seen[key]
	cl.mu.RUnlock()
	if exists {
		return true
	}

	cl.mu.Lock()
	defer cl.mu.Unlock()
	// Double-check after acquiring write lock
	if _, exists := cl.seen[key]; exists {
		return true
	}
	if len(cl.seen) >= cl.maxSeries {
		cl.overflowCnt++
		return false
	}
	cl.seen[key] = struct{}{}
	return true
}

func (cl *CardinalityLimiter) OverflowCount() int64 {
	cl.mu.RLock()
	defer cl.mu.RUnlock()
	return cl.overflowCnt
}

func (cl *CardinalityLimiter) CurrentSize() int {
	cl.mu.RLock()
	defer cl.mu.RUnlock()
	return len(cl.seen)
}

// sanitizeLabel normalizes and validates a label value.
// It truncates long values, removes dangerous characters, and lowercases.
func sanitizeLabel(value string, maxLen int) string {
	value = strings.TrimSpace(value)
	value = strings.ToLower(value)

	// Remove any characters that aren't alphanumeric, dash, underscore, or dot
	var b strings.Builder
	for _, r := range value {
		if (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') || r == '-' || r == '_' || r == '.' {
			b.WriteRune(r)
		}
	}
	value = b.String()

	if len(value) > maxLen {
		value = value[:maxLen]
	}

	if value == "" {
		value = "unknown"
	}
	return value
}

// bucketizeUserID maps user IDs into a fixed set of buckets using hashing.
// This prevents unbounded cardinality from arbitrary user IDs.
func bucketizeUserID(userID string, numBuckets int) string {
	h := sha256.Sum256([]byte(userID))
	hexStr := hex.EncodeToString(h[:4])
	// Parse first 4 bytes as uint32 and mod by numBuckets
	var val uint32
	for i := 0; i < 4; i++ {
		val = (val << 8) | uint32(h[i])
	}
	bucket := int(val) % numBuckets
	return fmt.Sprintf("bucket_%04d", bucket)
}

